P002_S0021.original:
\begin{equation}\label{eq:nu}
\nu_i = \frac{\rho_i m_i}{\langle a \rangle + \rho_i m_i}, \qquad \langle a \rangle = \sum_{j=1}^{k} p_j m_j (1 - \rho_j).
\end{equation}

P002_S0021.perturbed:
\begin{equation}\label{eq:nu}
\nu_i = \frac{\rho_i m_i}{\langle a \rangle - \rho_i m_i}, \qquad \langle a \rangle = \sum_{j=1}^{k} p_j m_j (1 - \rho_j).
\end{equation}

